import {
  LayoutDashboard,
  Upload,
  BarChart3,
  LineChart,
  Lightbulb,
  FileText,
} from "lucide-react";

const menu = [
  { name: "Dashboard", icon: LayoutDashboard },
  { name: "Upload", icon: Upload },
  { name: "Analysis", icon: BarChart3 },
  { name: "Visualization", icon: LineChart },
  { name: "Recommendations", icon: Lightbulb },
  { name: "Reports", icon: FileText },
];

export default function Sidebar() {
  return (
    <div className="w-64 bg-white border-r px-5 py-6">
      {/* LOGO */}
      <div className="flex items-center gap-3 mb-8">
        <div className="bg-green-600 text-white p-2 rounded-xl">🎓</div>
        <div>
          <h1 className="font-semibold text-lg">BloomLens</h1>
          <p className="text-sm text-gray-500">Exam Analyzer</p>
        </div>
      </div>

      <p className="text-xs text-gray-400 mb-3">Navigation</p>

      <div className="space-y-1">
        {menu.map((item, i) => {
          const Icon = item.icon;
          const active = i === 0;

          return (
            <div
              key={item.name}
              className={`flex items-center gap-3 px-4 py-2.5 rounded-lg cursor-pointer ${
                active
                  ? "bg-green-100 text-green-700"
                  : "text-gray-600 hover:bg-gray-100"
              }`}
            >
              <Icon size={18} />
              <span className="text-sm font-medium">{item.name}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
